#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 105;
const int M = 1e5+5;
const int INF = 0x3f3f3f3f;
int n,st,ed,St,Ed,d[M],dis[N];
int tot=1,head[M],to[M],wei[M],nxt[M];
queue<int> q;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Add_edge(int x,int y,int z){
    ++tot,to[tot]=y,wei[tot]=z;
    nxt[tot]=head[x],head[x]=tot;
    ++tot,to[tot]=x,wei[tot]=0;
    nxt[tot]=head[y],head[y]=tot;return;
}
void Insert_edge(int x,int y,int l,int r){
    Add_edge(x,y,r-l);
    d[x]-=l,d[y]+=l;return;
}
bool BFS_Canit(){
    for(int i=1;i<=Ed;i++)dis[i]=0;
    while(!q.empty())q.pop();
    dis[St]=1,q.push(St);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=head[u];i;i=nxt[i]){
            int v=to[i],w=wei[i];
            if(!w||dis[v])continue;
            dis[v]=dis[u]+1;
            if(v==Ed)return 1;q.push(v);
        }
    }return 0;
}
int DFS_Cntflow(int u,int flow){
    if(u==Ed)return flow;int now=flow;
    for(int i=head[u];i;i=nxt[i]){
        if(now<=0)break;
        int v=to[i],w=wei[i];
        if(!w||dis[v]!=dis[u]+1)continue;
        int tmp=DFS_Cntflow(v,min(now,w));
        if(!tmp)dis[v]=0;
        else wei[i]-=tmp,wei[i^1]+=tmp,now-=tmp;
    }return flow-now;
}
int main(){
    n=read();
    st=n+1,ed=n+2,St=n+3,Ed=n+4;
    for(int i=1;i<=n;i++){
        Insert_edge(st,i,0,INF);
        Insert_edge(i,ed,0,INF);
        int cnt=read();
        while(cnt--){
            int x=read();
            Insert_edge(i,x,1,INF);
        }
    }for(int i=1;i<=Ed;i++)
        if(d[i]>0)Add_edge(St,i,d[i]);
        else if(d[i]<0)Add_edge(i,Ed,-d[i]);else;
    while(BFS_Canit())
        while(DFS_Cntflow(St,INF));
    Insert_edge(ed,st,0,INF);
    while(BFS_Canit())
        while(DFS_Cntflow(St,INF));
    cout<<wei[tot]<<"\n";
    return 0;
}
